mapper.select:
SELECT COUNT(*)
FROM EMPLOYEE
WHERE LOGIN_ID = #{loginId}

SELECT E.EMP_ID AS empId, E.LOGIN_ID AS loginId, E.EMP_NAME AS empName, E.PHONE AS phone, E.EMAIL AS email, E.DEPT_ID AS deptId, D.DEPT_NAME AS deptName, E.ROLE_CODE AS roleCode, E.STATUS AS status, E.HIRE_DATE AS hireDate, E.CREATED_AT AS createdAt, E.UPDATED_AT AS updatedAt FROM EMPLOYEE E LEFT JOIN DEPARTMENT D ON E.DEPT_ID = D.DEPT_ID WHERE E.STATUS != 'TERMINATED'
AND E.DEPT_ID = #{deptId}
AND E.EMP_NAME LIKE '%' || #{empName} || '%'
AND E.ROLE_CODE = #{roleCode}
ORDER BY E.EMP_ID DESC
